4	// MARK: - Protocol
5	
6	/// Single source of truth for user-adjustable runtime behaviour.
7	/// Injectable so tests can swap in `InMemoryAppPreferences`.
8	@MainActor
9	public protocol AppPreferences: AnyObject, Observable, Sendable {
10	    var refreshInterval: RefreshInterval { get set }
11	    var launchAtLogin: Bool { get set }
12	    var logLevel: LogLevel { get set }
13	    var menuBarSegments: [MenuBarSegmentConfig] { get set }
14	    /// Tracks whether seeding has already run — distinguishes "fresh install"
15	    /// from "user deleted all segments." False on a brand-new UserDefaults suite.
16	    var menuBarSegmentsInitialized: Bool { get set }
17	}
18	
19	// MARK: - UserDefaults-backed implementation
20	
21	@Observable
22	@MainActor
23	public final class UserDefaultsAppPreferences: AppPreferences {
24	    private let defaults: UserDefaults
25	
26	    public init(defaults: UserDefaults = .standard) {
27	        self.defaults = defaults
28	    }
29	
30	    public var refreshInterval: RefreshInterval {
31	        get {
32	            let raw = defaults.integer(forKey: AppPreferenceKeys.refreshIntervalSeconds.rawValue)
33	            if raw == 0 { return .default }
34	            return RefreshInterval(clamping: raw)
35	        }
36	        set {
37	            defaults.set(newValue.seconds, forKey: AppPreferenceKeys.refreshIntervalSeconds.rawValue)
38	        }
39	    }
